<template>
  <div class="production-name flexrow" v-if="production">
    <span
      class="flexrow-item avatar has-text-centered"
      :style="{
        background: avatarColor,
        width: `${size}px`,
        height: `${size}px`,
        fontSize: `${Math.max(size - 15, 10)}px`,
        lineHeight: `${size}px`
      }"
      :title="production.name"
      v-if="withAvatar"
    >
      <template v-if="!production.has_avatar">{{ avatar }}</template>
      <img
        :src="thumbnailPath"
        :style="{
          width: `${size}px`,
          height: `${size}px`
        }"
        v-else
      />
    </span>
    <span
      class="flexrow-item avatar-name"
      :style="{
        'margin-left': withAvatar ? '0.8em' : '0'
      }"
      v-if="!onlyAvatar"
    >
      {{ production.name }}
    </span>
  </div>
</template>

<script setup>
import { computed } from 'vue'
import colors from '@/lib/colors.js'

const props = defineProps({
  onlyAvatar: {
    default: false,
    type: Boolean
  },
  production: {
    default: () => {},
    type: Object
  },
  size: {
    default: 40,
    type: Number
  },
  withAvatar: {
    default: true,
    type: Boolean
  }
})

const avatar = computed(() => {
  const firstLetter = props.production.name[0] || 'P'
  return firstLetter.toUpperCase()
})

const avatarColor = computed(() => {
  return colors.fromString(props.production.name)
})

const thumbnailPath = computed(() => {
  const lastUpdate = props.production.updated_at || props.production.created_at
  const timestamp = Date.parse(lastUpdate)
  return `/api/pictures/thumbnails/projects/${props.production.id}.png?t=${timestamp}`
})
</script>

<style lang="scss" scoped>
.flexrow-item {
  margin: 0;
}

.avatar-name {
  color: $black;

  .dark & {
    color: $white;
  }
}

@media screen and (max-width: 768px) {
  .avatar-name {
    display: none;
  }
}
</style>
